import { useEffect, useState, useCallback } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [bugs, setBugs] = useState([]);
  const [filter, setFilter] = useState("all");
  const [wallet, setWallet] = useState(0);

  const token = localStorage.getItem("token");

  // ================= FETCH DATA =================
  const fetchCompanyBugs = useCallback(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => setBugs(data.bugs || data || []));
  }, [token]);

  const fetchWallet = useCallback(() => {
    fetch("http://localhost:5000/api/bugs/company/wallet", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => setWallet(data.walletBalance || 0));
  }, [token]);

  useEffect(() => {
    const role = localStorage.getItem("role");
    if (!token) return (window.location.href = "/");
    if (role !== "company" && role !== "admin")
      return (window.location.href = "/hacker");

    fetchCompanyBugs();
    fetchWallet();
  }, [fetchCompanyBugs, fetchWallet, token]);

  // ================= STATS =================
  const total = bugs.length;
  const approved = bugs.filter(b => b.status === "approved").length;
  const rejected = bugs.filter(b => b.status === "rejected").length;
  const paid = bugs
    .filter(b => b.status === "approved")
    .reduce((sum, b) => sum + (b.reward || 0), 0);

  const filteredBugs =
    filter === "all" ? bugs : bugs.filter(b => b.status === filter);

  return (
    <div className="company-dashboard">
      {/* HEADER */}
      <header className="company-header">
        <h1>🏢 Company Dashboard</h1>
        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {/* STATS */}
      <section className="stats-row">
        <div className="stat-card">🐞 Total Bugs <span>{total}</span></div>
        <div className="stat-card approved">✅ Approved <span>{approved}</span></div>
        <div className="stat-card rejected">❌ Rejected <span>{rejected}</span></div>
        <div className="stat-card paid">💰 Paid <span>₹{paid}</span></div>
      </section>

      {/* FILTERS */}
      <section className="filters">
        {["all", "submitted", "approved", "rejected"].map(s => (
          <button
            key={s}
            className={filter === s ? "active" : ""}
            onClick={() => setFilter(s)}
          >
            {s.toUpperCase()}
          </button>
        ))}
      </section>

      {/* BUG CARDS */}
      <section className="bug-grid">
        {filteredBugs.length === 0 ? (
          <p className="muted">No bugs found.</p>
        ) : (
          filteredBugs.map(bug => (
            <div className="bug-card" key={bug._id}>
              <div className="bug-header">
                <h3>{bug.title}</h3>
                <span className={`status ${bug.status}`}>{bug.status}</span>
              </div>

              <p className="bug-desc">{bug.description}</p>

              <div className="bug-meta">
                <span className={`severity ${bug.severity}`}>{bug.severity}</span>
                <span className="email">🧑‍💻 {bug.submittedBy?.email}</span>
              </div>
            </div>
          ))
        )}
      </section>

      {/* WALLET */}
      <section className="wallet-box">
        <h3>💰 Wallet</h3>
        <p>Balance: <b>₹{wallet}</b></p>
        <button className="topup-btn">Top Up Wallet</button>
      </section>
    </div>
  );
}
